var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 정도로는 날 쓰러트릴 수 없다!","JPN":"その程度では私は倒せない！","ENG":"You'll have to do better than this!","TWN":"這種程度可沒辦法讓我倒下！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"죽어라! 괴물!","JPN":"死ぬがいい！　化け物！","ENG":"Die! Monster!","TWN":"去死吧！怪物！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......크윽.","JPN":"くうっ……","ENG":"Ugh.","TWN":"……咳咳。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"약해졌다고는 해도 확실히 단단하군.","JPN":"弱くなったとはいえ、堅さは間違いないな。","ENG":"It might have become weaker, but it's still as tough as ever.","TWN":"雖然它變弱了，但還是很堅硬啊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"내 전력으로도 놈의 중추를 파괴하는 건 무리인 건가?","JPN":"私の全力でも奴の中枢を破壊するのは無理なのか？","ENG":"Is my full power not enough to destroy its core?","TWN":"靠我的戰鬥力也沒辦法破壞它的中樞神經嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아니, 아무것도 바뀐 건 없다.","JPN":"いや、何も変わったことはない。","ENG":"No, nothing has changed.","TWN":"不，我絕不會動搖。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"열번이든 백번이든, 파괴될 때까지 공격할 뿐!","JPN":"10回でも100回でも、破壊できるまで攻撃するのみ！","ENG":"Ten times, a hundred times; I'll keep attacking until it's destroyed!","TWN":"不管是十次還是一百次，攻擊到破壞它為止！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부사령관님! 피하세요!","JPN":"副司令官！　避けてください！","ENG":"Deputy Commander! Get away from here!","TWN":"副司令官大人！快躲開！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L22_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"너야말로 물러서라! 제이나! 넌 몸도 정상이 아니야!","JPN":"お前こそ下がれ！ ジェイナ、お前は万全ではない！","ENG":"No, YOU back off, Jaina! You're not in your best condition!","TWN":"還是你走吧！婕娜！你現在的身體狀態很不好！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"더 이상 힘을 썼다간 CRF가 고갈될 거다! 그림자로 변할 수도 있어!","JPN":"これ以上力を使うとCRFが枯渇するぞ！　シャドウになりたいのか！？","ENG":"You'll deplete your CRF if you use any more power! You could turn into a Shadow!","TWN":"如果繼續戰鬥，CRF會枯竭的！你可能會變成暗影！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"처음 만났을 때 말했었지? 내가 널 퇴치하도록 만들지 마라!","JPN":"初めて会った時に言ったはずだ。私に退治される羽目になりたくなければ、大人しく待機しろ！","ENG":"Remember what I told you when we first met? Don't make me exterminate you!","TWN":"第一次見面時，我就跟你說過吧？別讓我有出手消滅你的那天！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"부사령관님이야 말로 제가 왜 이런 무저갱에 떨어졌다고 생각하시는 겁니까?!","JPN":"副司令官こそ、なぜ私がこんな地獄の底のような場所に落ちたと思っているのですか？","ENG":"No, you're the one who doesn't understand why I fell into this bottomless pit!","TWN":"副司令官大人您覺得當初為什麼我選擇進入這個無底洞？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"당신을 살리기 위해서였어요!","JPN":"あなたに生きてほしいからです！","ENG":"It was to save you!","TWN":"是為了救你！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그 모든 걸 헛되게 만드는 건...... 제가 용납하지 않겠습니다!","JPN":"そのすべてを無駄にすることは……私が許せません！","ENG":"I won't let everything I've been through go to waste!","TWN":"別讓我的心血白費…… 我絕不接受！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"덤벼! 이 괴물아! 널 여기로 추락시킨 건 나다!!","JPN":"かかってきなさい、この化け物！　お前をここに落としたのは私だ！","ENG":"Come at me, you monster! I'm the one who put you here!","TWN":"來吧！你這個怪物！讓你墜落到這裡的人是我！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"제이나! 멈춰!!","JPN":"ジェイナ！　やめろ！","ENG":"Jaina! Stop!","TWN":"婕娜！快停下！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_ENERGY_CHARGE"},{"id":"L37_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"크윽...... 제이나? 괜찮은가? 제이나!","JPN":"くっ……ジェイナ？　大丈夫か？　ジェイナ！","ENG":"Ugh... Jaina? Are you alright? Jaina!","TWN":"咳……婕娜？你沒事吧？婕娜！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"......저, 전 괜찮습니다. 그보다 저건......?","JPN":"……わ、私は無事です。ところであれは……？","ENG":"I-I'm fine. But what was that?","TWN":"……我，我沒事。不過那個是……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_COFFIN_START_02"},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 제가 아주 적당한 타이밍에 도착한 것 같군요.","JPN":"ハハ、ちょうどいいタイミングに着いたようですね。","ENG":"Hah hah, it seems I've arrived at a very appropriate time.","TWN":"哈哈，看來我來的正是時候。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"조금만 늦었으면 큰일날 뻔 했어요.","JPN":"少しでも遅かったら、大変なことになるところでしたね。","ENG":"It might've been a disaster if I came a little later.","TWN":"如果再晚一步就出大事了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......나유빈?","JPN":"……イチノセ・カオル？","ENG":"Na Yubin?","TWN":"……羅瑜斌？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"조금 전 공격은 네가 막은 건가?","JPN":"先ほどの攻撃はお前が防いだのか？","ENG":"Did you just block the last attack?","TWN":"剛才的攻擊是你抵擋的嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네. 그 대단한 네임리스 원의 공격이라고 해서 꽤나 긴장했는데 생각보다는 별거 아니군요.","JPN":"はい。あのネームレスワンの攻撃なのでかなり緊張しましたが、思ったより大したことないですね。","ENG":"Yes. I was worried if I could really ward off an attack from the notorious Nameless One, but it wasn't as formidable as I expected.","TWN":"是啊。本來因為是聲名赫赫的無名1所發出的攻擊，我還緊張得不行。沒想到不過如此。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"비웃고 싶다면 마음대로 해라. 하지만 놈의 원래 힘은 이 정도가 아니었어.","JPN":"あざ笑いたいなら勝手にしろ。しかし、奴の本来の力はこの程度ではなかった。","ENG":"Laugh if you want. But that monster's power was much stronger back then.","TWN":"如果你想嘲笑的話，隨意吧。但它原本的力量不僅僅是這種程度。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이유는 모르겠지만 놈은 지금 약해진 상태다.","JPN":"理由はわからないが、奴は今弱っている状態だ。","ENG":"We don't know why, but it's weak right now.","TWN":"雖然不知道原因，但它現在變弱了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"보다시피 육체도 저런 고치로 바뀌어 버렸으니까.","JPN":"見てのとおり、肉体もあのような繭になっている。","ENG":"As you can see, its body turned into a cocoon.","TWN":"你也看到它的肉身已經變成了那樣的卵囊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"과연 그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하긴 진짜 5종 침식체의 공격이었다면 저도 이렇게 쉽게 받아내긴 어려웠겠죠.","JPN":"確かに、本当に第5種侵食体の攻撃なら、僕もさっきのように簡単に返すのは難しかったでしょう。","ENG":"I guess it wouldn't have been so easy to block a real Category 5 C.O.'s attack.","TWN":"也是，如果真的是5類侵蝕體的攻擊，我也很難如此輕鬆地抵擋住吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"말은 들었지만 실제로 보니 아주 재미있게 <color=#ffd34c>설계</color>해둔 것 같군요.","JPN":"噂には聞いていましたが実際に見てみると、とても面白そうな<color=#ffd34c>設計</color>ですね。","ENG":"As I've heard, it has a rather intriguing <color=#ffd34c>design</color>.","TWN":"雖然之前聽說過，但實際見到之後感覺<color=#ffd34c>設計</color>得很有意思。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"설계......?","JPN":"設計……？","ENG":"Design?","TWN":"設計……？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"다, 당신은 누구지?!","JPN":"あ、あなたは誰！？","ENG":"W-who are you?","TWN":"你、你是誰？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"물러나세요, 부사령관님. 저 자에게선 뭔가 위험한 냄새가 납니다.","JPN":"下がってください、副司令官。あの者からは危険な匂いがします。","ENG":"Stay back, Deputy Commander. That man smells of danger.","TWN":"請退到我後邊，副司令官大人。他的身上有某種危險的味道。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"처음 본 사이인데 그렇게 경계하시니 조금 섭섭하네요.","JPN":"初対面なのに、そこまで警戒されたら少し寂しくなります。","ENG":"I'm a little disappointed that you're so wary of me, even though it's our first acquaintance.","TWN":"第一次見面就這麼警惕，真讓我有些難過啊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전 레지날드씨의 성실한 조력자입니다.","JPN":"僕はレジナルドさんの誠実な協力者です。","ENG":"I'm Mr. Reginald's diligent helper...","TWN":"我可是這位副司令官多明尼克的忠實幫手。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 주민들에게 사랑 받는 지역 공무원이기도 하죠.","JPN":"そして、地域の住民に愛される公務員でもあります。","ENG":"and also a civil worker loved by local residents.","TWN":"同時還是深受居民們喜愛的地區公務員。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"지역 공무원? 무슨 헛소릴 하는 거냐!","JPN":"公務員？　ふざけたことを言うな！","ENG":"Civil worker? Don't you lie in front of me!","TWN":"地區公務員？你在胡說什麼！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"괜찮다, 제이나. 물러서.","JPN":"大丈夫だ、ジェイナ。下がっていろ。","ENG":"It's fine, Jaina. Step back.","TWN":"沒關係，婕娜。退後吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"여기에 널 찾으러 올 수 있었던 건 저 자가 제공한 구 관리국의 기술 덕분이었다.","JPN":"ここまでお前を探しに来れたのは、あの者が提供した旧管理局の技術のおかげだ。","ENG":"I found you thanks to the Old Administration technology he provided.","TWN":"能到這裡來找你，是多虧他提供的舊管理局技術。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"수상하고 위험한 자라는 건 분명하지만 적어도 지금은 적이 아니야.","JPN":"怪しく危険な者ということは確かだが、少なくとも今ここで敵視する必要はない。","ENG":"He might be suspicious and dangerous, but he's not our enemy for now.","TWN":"雖然他是可疑又危險的人，但至少現在不是敵人。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇습니다. 그리고 지금 여러분이 적대해야 할 건 제가 아니라 저 괴물이 아닐까요?","JPN":"そうですよ。そして今、皆さんが敵対すべきものは僕ではなく、あの怪物ではないでしょうか？","ENG":"That's right. It's that monster you should be fighting, not me.","TWN":"對啊。現在各位要對付的可不是我，而是那個怪物吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"아니, 굳이 그런 위험을 감수할 필요는 없어.","JPN":"いや、あえて危険を冒す必要はない。","ENG":"No, we don't need to take that risk.","TWN":"不，沒必要非得冒這種危險。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"여기까지 왔다면 돌아갈 방법도 있다는 거겠지?","JPN":"ここまで来れたなら、帰る方法も知っているのでは？","ENG":"If you were able to come here, you must have a way back.","TWN":"能來到這裡，不就說明還有回去的方法嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"놈을 이 곳에 묶어두고 우리끼리만 탈출하면 될 일이야.","JPN":"奴をここに足止めさせて、私たちだけ脱出すればいい。","ENG":"We just need to immobilize this monster and escape by ourselves.","TWN":"把它捆在這裡，我們離開就可以了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아쉽지만 그건 어렵겠어요.","JPN":"残念ですが、それは厳しそうです。","ENG":"Unfortunately, that's not an option.","TWN":"很遺憾，這樣不行。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저와 레지날드씨는 네임리스 원의 사체를 인양하기 위해 이곳에 왔거든요.","JPN":"僕とレジナルドさんはネームレスワンの遺骸を引き揚げるために、ここに来たんですよ。","ENG":"Mr. Reginald and I came here to salvage the Nameless One's carcass.","TWN":"我和多明尼克來這裡是為了撈起無名1的屍體。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니 돌아가는 건 저 계란 친구를 밟아 깨트린 후로 하죠.","JPN":"だから戻るのは、あの卵をつぶしてからにしましょう。","ENG":"So we're going back after we break that egg friend of ours.","TWN":"所以，想要回去，得先把那個像卵囊的無名1踩碎再說吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"잘도 쉽게 그런 소리를......","JPN":"よくそんなことを簡単に……","ENG":"That's easy for you to say—","TWN":"說的倒是輕鬆……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론 말로만 도와드리겠다는 건 아니에요.","JPN":"もちろん、口先ばかりではありませんよ。","ENG":"Of course, I'm not just paying lip service.","TWN":"當然我不是靠吹牛來幫你們的。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제 성의를 보여드리는 의미로 제이나 씨에게 이걸 선물하도록 하죠.","JPN":"僕からの誠意として、ジェイナさんにはこれをプレゼントしましょう。","ENG":"I'll give you this, Jaina, as a sign of my sincerity.","TWN":"為了讓你們看見我的誠意，我把這個送給婕娜小姐吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"이건......","JPN":"これは……","ENG":"What...","TWN":"這是……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"뭐, 뭐야? 이 노출증 환자 같은 옷은!","JPN":"な、なに？　この露出狂みたいな服は？","ENG":"W-what's this perverted dress?","TWN":"這、這是什麼？像暴露狂穿的衣服！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"지금 나보고 이걸 입으라고?!","JPN":"こんな物を今私に着ろということか！？","ENG":"You can't possibly ask me to wear that!","TWN":"你現在讓我穿這個？！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"네 녀석이 속내를 짐작하기 힘든 남자라는 건 잘 알고 있었지만 이건 정말 의외로군.","JPN":"お前が腹の底が読めない男ということはすでに知っていたが、これは本当に意外だな。","ENG":"I knew it would be hard to guess what you were doing, but this was completely unpredictable.","TWN":"我雖然知道你是個難以被看破內心的男人，不過你這種舉動真是太出乎意料之外了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"대체 무슨 생각이지? 질 나쁜 농담 같은 건가?","JPN":"いったい何のつもりだ？　質の悪いイタズラか？","ENG":"What are you thinking? Is this some sort of bad joke?","TWN":"你到底在想什麼？是在搞惡作劇嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 죄송합니다. 제가 설명이 부족했군요.","JPN":"ハハ、すみません。説明が足りなかったようですね。","ENG":"Hah hah, my apologies. I should've explained in more detail.","TWN":"哈哈，抱歉。我忘了說清楚。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이건 구 관리국에서 제작한 고등급 카운터 전용의 특수 전투복입니다.","JPN":"こちらは旧管理局が製作した高等級カウンター専用の特殊戦闘服です。","ENG":"This is a special combat suit made by the Old Administration, exclusively for high-grade Counters.","TWN":"這是舊管理局製作的高級制裁者專用特殊戰鬥服。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"자체 방어력은 물론 착용자의 힘을 훨씬 증폭시켜주는 역할을 하죠.","JPN":"服自体の防御力はもちろん、着用者の力をさらに増幅させる役割があります。","ENG":"It increases the wearer's power as well as defense.","TWN":"不僅有自身防禦力，還有大幅度增強使用者力量的功能。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 옷을 입으면 그림자가 되기 직전인 당신도 충분히 저 고치를 상대할 수 있을 겁니다.","JPN":"この服を着ればシャドウになる直前のあなたでも、十分にあの繭を相手に戦えるでしょう。","ENG":"Even you, who's on the brink of becoming a Shadow, will be able to fight that monster if you wear this suit.","TWN":"穿上這件衣服，就算是即將變成暗影的你，也有足夠的能力對付那個卵囊。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론 디자인은...... 좀 파격적이긴 하죠.","JPN":"まあ、デザインは……多少変わっていますが。","ENG":"I do admit its design is quite, err, unconventional.","TWN":"當然設計是有些…… 是有那麼點過於搶眼。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이걸 만든 분의 취향이 뭐랄까...... 일반인이 이해하기 힘든 분이시라서요.","JPN":"これを作った方の好みというか……一般人が理解するのは難しいでしょう。","ENG":"The maker of this piece has a taste which... ordinary people rarely understand.","TWN":"只能說設計師的喜好…… 是讓普通人難以理解的。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 성능은 확실합니다. 제가 보장하죠.","JPN":"しかし性能は確かです。僕が保証しましょう。","ENG":"But you can trust its performance. I'll guarantee that.","TWN":"但我保證功能值得肯定。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"별로 신뢰하고 싶진 않지만, 선택의 여지가 없군.","JPN":"あまり信用したくないけど、選択の余地はないか。","ENG":"I don't want to trust you, but it seems I've got no choice.","TWN":"雖然我不想相信，但沒選擇的餘地了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어때요? 신비한 힘이 느껴지지 않나요?","JPN":"どうですか？　不思議な力を感じませんか？","ENG":"How is it? Can you feel the mysterious power?","TWN":"怎麼樣？感受到神秘的力量了嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"뭐라고 한 마디 해주고 싶지만...... 그래, 성능은 확실한 것 같군.","JPN":"一言言ってやりたいが……性能は確かなようだ。","ENG":"I'd love to shut that mouth of yours, but yes, the performance is solid.","TWN":"雖然很想說髒話…… 但的確是，功能完全沒問題。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 알아주실 거라고 생각했습니다.","JPN":"ハハ、わかってもらえてよかったです。","ENG":"Hah hah, I knew you'd notice.","TWN":"哈哈，我就知道你能明白。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아, 유감이지만 레지날드 씨를 위한 전투복은 챙겨오질 못했어요.","JPN":"ああ、残念ながらレジナルドさんのための戦闘服は持ってきていません。","ENG":"Ah, I'm afraid I couldn't prepare a combat suit for you, Mr. Reginald.","TWN":"啊，很遺憾，我沒帶多明尼克可以穿的戰鬥服。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다음에 시간이 되면 재고품이 있는지 찾아보도록 하죠.","JPN":"今度時間がある時に、在庫がないか探してみます。","ENG":"I'll see if there's any extras when I have the time.","TWN":"下次有時間，我會找找看有沒有庫存。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......아니, 그럴 필요는 없다. 고맙지만 사양하도록 하지.","JPN":"……いや、その必要はない。ありがたい話だが、遠慮しておこう。","ENG":"No, that's unnecessary. I'll decline.","TWN":"……不用，沒那個必要。感謝你，但還是算了吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"......놈이 다시 정신을 차린 것 같군요.","JPN":"……奴がまた動き出したようです。","ENG":"It seems the monster has regained consciousness.","TWN":"……那傢伙好像重新醒過來了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"좋아, 2회전이로군.","JPN":"よし、2回戦だな。","ENG":"Great, time for round two.","TWN":"很好。那就開始第二回合吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"준비는 되었나, 제이나?","JPN":"準備はいいか、ジェイナ？","ENG":"Are you ready, Jaina?","TWN":"準備好了嗎？婕娜？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"네, 부사령관님!","JPN":"はい、副司令官！","ENG":"Yes, sir!","TWN":"是的。副司令官大人！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAINA_DELTA_TRANS_NULL","text":{"KOREA":"다시 함께 싸우게 되어 영광입니다.","JPN":"再び一緒に戦うことができて光栄です。","ENG":"It's an honor to be able to fight with you again.","TWN":"能重新與您並肩戰鬥是我的光榮。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_TRANS_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};